book-air-m3', 'Incredibly thin and light laptop with M3 chip.', 'https://images.unsplash.com/photo-1517336714731-489689fd1ca8?w=600&h=600&fit=crop', 1099.0, 40, 1),\n  (4, 1, 'Dell XPS 15', 'dell-xps-15', 'Powerful laptop for creators with stunning OLED display.', 'https://images.unsplash.com/photo-1593642702821-c823b13eb2a2?w=600&h=600&fit=crop', 1899.99, 32, 0),\n  (5, 1, 'Sony WH-1000XM5 Headphones', 'sony-wh-1000xm5', 'Industry-leading noise canceling over-ear headphones.', 'https://images.unsplash.com/photo-1618366712010-f4ae9c647dcb?w=600&h=600&fit=crop', 349.99, 110, 1),\n  (6, 1, 'Apple Watch Series 9', 'apple-watch-series-9', 'Advanced health tracking smartwatch.', 'https://images.unsplash.com/photo-1546868871-7041f2a55e12?w=600&h=600&fit=crop', 399.0, 75, 0),\n  (7, 1, 'Canon EOS R5 Camera', 'canon-eos-r5', 'Professional mirrorless camera for stunning photography.', 'https://images.unsplash.com/photo-1516035069371-29a1b244cc32?w=600&h=600&fit=crop', 3899.0, 15, 0),\n  (8, 1, 'Samsung 65-Inch 4K TV', 'samsung-65-4k-tv', 'Breathtaking 4K UHD Smart TV.', 'https://images.unsplash.com/photo-1593305841991-05c297ba4575?w=600&h=600&fit=crop', 1250.0, 20, 0),\n  (9, 1, 'JBL Charge 5 Speaker', 'jbl-charge-5', 'Portable Bluetooth speaker with deep bass.', 'https://images.unsplash.com/photo-1608043152269-423dbba4e7e1?w=600&h=600&fit=crop', 149.95, 140, 0),\n  (10, 1, 'Keychron Q1 Pro Keyboard', 'keychron-q1-pro', 'Custom mechanical keyboard for enthusiasts.', 'https://images.unsplash.com/photo-1595225476474-87563907a212?w=600&h=600&fit=crop', 199.0, 55, 0),\n  (11, 2, 'Nike Air Max 270', 'nike-air-max-270', 'Comfortable, stylish everyday sneakers.', 'https://images.unsplash.com/photo-1600181516264-3ea807fe3772?w=600&h=600&fit=crop', 150.0, 130, 1),\n  (12, 2, 'Levi''s 501 Original Jeans', 'levis-501-original', 'Classic straight leg denim jeans.', 'https://images.unsplash.com/photo-1542272604-787c3835535d?w=600&h=600&fit=crop', 69.5, 200, 0),\n  (13, 2, 'Puma Graphic H